from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable, Iterable
from typing import Any


async def _cancel_and_wait(tasks: set[asyncio.Task[Any]]) -> None:
    if not tasks:
        return

    for task in tasks:
        task.cancel()

    current = asyncio.current_task()
    uncancel_count = 0

    # Temporarily clear cancellation on the parent task so child-task cleanup
    # can finish before cancellation is re-raised to the caller.
    if current is not None:
        while current.cancelling():
            current.uncancel()
            uncancel_count += 1

    try:
        await asyncio.gather(*tasks, return_exceptions=True)
    finally:
        if current is not None:
            for _ in range(uncancel_count):
                current.cancel()


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    pending = iter(tasks)
    active: set[asyncio.Task[Any]] = set()

    def start_next() -> bool:
        try:
            task_fn = next(pending)
        except StopIteration:
            return False

        active.add(asyncio.create_task(task_fn()))
        return True

    for _ in range(min(max_concurrent, len(tasks))):
        start_next()

    while active:
        try:
            done, _ = await asyncio.wait(active, return_when=asyncio.FIRST_COMPLETED)
        except BaseException:
            await _cancel_and_wait(active)
            raise

        task_error: BaseException | None = None

        for task in done:
            active.remove(task)

            try:
                task.result()
            except BaseException as exc:
                if task_error is None:
                    task_error = exc

        if task_error is not None:
            await _cancel_and_wait(active)
            raise task_error

        while len(active) < max_concurrent and start_next():
            pass
